from http.server import BaseHTTPRequestHandler, HTTPServer
from urllib.parse import parse_qs
from datetime import datetime
import csv, html, os
BRAND="Grad Gallery"
PORT=int(os.environ.get("PORT","8765"))
CSV_PATH=os.path.join(os.path.dirname(__file__),"grad_gallery_bookings.csv")
PACKAGES=[("Budget","$150","30 min","1 location, 5 edited images"),("Standard","$250","1 hour","1-2 locations, 10 edited images"),("Premium","$400","1.5 hours","2-3 locations, 18 edited images")]
PHOTOGRAPHERS=[('Shotsbydavi', 'Standard', 'data:image/jpeg;base64,'), ('Artwithinfocus', 'Budget', 'data:image/jpeg;base64,'), ('JayHutchh', 'Premium', 'data:image/jpeg;base64,'), ('pheonlens', 'Standard', 'data:image/jpeg;base64,'), ('Moodscape.photography', 'Budget', 'data:image/jpeg;base64,'), ('Shots from SEA', 'Budget', 'data:image/jpeg;base64,')]
STATUSES=["New inquiry","Needs follow-up","Photographer pending","Awaiting payment","Confirmed","Session completed","Gallery delivered","Photographer paid","Canceled"]
def e(x): return html.escape(str(x or ""),quote=True)
def layout(title,body):
 return f"""<!doctype html><html><head><meta charset=utf-8><meta name=viewport content='width=device-width,initial-scale=1'><title>{e(title)} | {BRAND}</title><style>*{{box-sizing:border-box}}body{{margin:0;font-family:Arial,sans-serif;background:#fbfaf7;color:#171717}}a{{color:inherit;text-decoration:none}}header{{position:sticky;top:0;background:#fbfaf7ee;border-bottom:1px solid #ddd5ca}}nav{{max-width:1100px;margin:auto;padding:16px 20px;display:flex;justify-content:space-between;gap:14px;flex-wrap:wrap}}.logo{{font-weight:900;letter-spacing:.04em}}.links{{display:flex;gap:14px;flex-wrap:wrap;color:#68615a;font-size:14px}}main,.section{{max-width:1100px;margin:auto;padding:34px 20px}}.hero{{display:grid;grid-template-columns:1.1fr .9fr;gap:24px;align-items:center;padding-top:56px}}h1{{font-size:clamp(40px,7vw,74px);line-height:.94;margin:0 0 18px}}h2{{font-size:30px;margin:0 0 12px}}p{{color:#68615a;line-height:1.55}}.btn{{display:inline-flex;padding:13px 18px;border-radius:8px;background:#171717;color:white;font-weight:800;border:0;cursor:pointer}}.btn.alt{{background:white;color:#171717;border:1px solid #ddd5ca}}.actions{{display:flex;gap:10px;flex-wrap:wrap;margin-top:20px}}.grid{{max-width:1100px;margin:auto;padding:20px;display:grid;grid-template-columns:repeat(3,1fr);gap:14px}}.card,.panel{{background:white;border:1px solid #ddd5ca;border-radius:8px;padding:18px}}.price{{font-size:34px;font-weight:900}}.badge{{display:inline-flex;padding:5px 9px;border-radius:999px;background:#efe7d9;color:#6b4519;font-size:12px;font-weight:800}}.person{{display:flex;gap:12px;align-items:center}}.photo{{width:54px;height:54px;border-radius:50%;object-fit:cover;border:1px solid #ddd5ca}}form{{display:grid;gap:14px;max-width:760px}}label{{font-weight:800;font-size:14px}}input,select,textarea{{width:100%;padding:12px;border:1px solid #ddd5ca;border-radius:8px;font:inherit;background:white}}textarea{{min-height:96px}}.checks{{display:grid;grid-template-columns:repeat(2,1fr);gap:10px}}.checks label{{display:flex;gap:8px;align-items:center;background:white;border:1px solid #ddd5ca;border-radius:8px;padding:10px;font-weight:600}}.checks input{{width:auto}}table{{width:100%;border-collapse:collapse;background:white}}th,td{{padding:10px;border:1px solid #ddd5ca;text-align:left;font-size:14px}}th{{background:#f1ece4}}footer{{padding:28px;text-align:center;color:#68615a}}@media(max-width:820px){{.hero,.grid,.checks{{grid-template-columns:1fr}}}}</style></head><body><header><nav><a class=logo href=/>GRAD GALLERY</a><div class=links><a href=/packages>Packages</a><a href=/photographers>Photographers</a><a href=/book>Book</a><a href=/admin>Tracker</a></div></nav></header>{body}<footer>Grad Gallery - ODU graduation portrait booking made simple.</footer></body></html>"""
def home():
 cards=''.join(f"<div class=card><span class=badge>{n}</span><div class=price>{pr}</div><h3>{tm}</h3><p>{det}</p></div>" for n,pr,tm,det in PACKAGES)
 return layout('Home',f"<main class='hero'><section><h1>Graduation photos made simple.</h1><p>Choose your package, choose your photographer, and request your ODU grad session without the back-and-forth.</p><div class=actions><a class=btn href=/book>Start Booking</a><a class='btn alt' href=/photographers>View Photographers</a></div></section><aside class=panel><h2>Spring 2027 bookings</h2><p>Built for ODU grads who want clear prices, trusted photographers, and a smoother way to book.</p><p><b>Simple flow:</b> package -> photographer -> date -> payment -> session.</p></aside></main><section class=grid>{cards}</section>")
def packages():
 rows=''.join(f"<tr><td><b>{n}</b></td><td>{pr}</td><td>{tm}</td><td>{det}</td></tr>" for n,pr,tm,det in PACKAGES)
 return layout('Packages',f"<section class=section><h1>Packages</h1><p>Three clear options for different budgets and expectations.</p><table><tr><th>Package</th><th>Price</th><th>Time</th><th>Includes</th></tr>{rows}</table><div class=actions><a class=btn href=/book>Book a Session</a></div></section>")
def photographers():
 cards=''.join(f"<div class='card person'><img class=photo src='{img}' alt='{e(n)}'><div><h3>{e(n)}</h3><span class=badge>{e(t)}</span><p>Available for {e(t).lower()} Grad Gallery sessions.</p></div></div>" for n,t,img in PHOTOGRAPHERS)
 return layout('Photographers',f"<section class=section><h1>Photographers</h1><p>Students can pick from photographers that fit their package level.</p></section><section class=grid>{cards}</section>")
def book(ok=False):
 po=''.join(f"<option>{n}</option>" for n,_,_,_ in PACKAGES); pho=''.join(f"<option>{e(n)}</option>" for n,_,_ in PHOTOGRAPHERS)
 msg='<div class=panel><h2>Request received</h2><p>Your inquiry has been saved. Grad Gallery will follow up to confirm availability and payment.</p></div>' if ok else ''
 checks=''.join(f"<label><input type=checkbox name=wants value='{x}'>{x}</label>" for x in ['Cap and gown','Family photos','Friend photos','Social media photos','Extra outfit','Extra location'])
 return layout('Book',f"<section class=section><h1>Book Grad Photos</h1><p>Fill this out once. Select all that apply so the session matches what you need.</p>{msg}<form method=post action=/submit><label>Full name<input name=name required></label><label>Email<input type=email name=email required></label><label>Phone<input name=phone></label><label>Package<select name=package>{po}</select></label><label>Preferred photographer<select name=photographer>{pho}<option>Not sure yet</option></select></label><label>Graduation term<input name=grad_term placeholder='Spring 2027'></label><label>Preferred date/time<textarea name=availability></textarea></label><label>What do you want included?</label><div class=checks>{checks}</div><label>Notes<textarea name=notes></textarea></label><button class=btn>Submit Booking Request</button></form></section>")
def save(f):
 heads=['created_at','status','name','email','phone','package','photographer','grad_term','availability','wants','notes']; exists=os.path.exists(CSV_PATH)
 row={k:'' for k in heads}; row.update({'created_at':datetime.now().strftime('%Y-%m-%d %H:%M'),'status':'New inquiry','wants':'; '.join(f.get('wants',[]))})
 for k in ['name','email','phone','package','photographer','grad_term','availability','notes']: row[k]=f.get(k,[''])[0]
 with open(CSV_PATH,'a',newline='',encoding='utf-8') as out:
  w=csv.DictWriter(out,fieldnames=heads)
  if not exists: w.writeheader()
  w.writerow(row)
def admin():
 rows=''
 if os.path.exists(CSV_PATH):
  with open(CSV_PATH,newline='',encoding='utf-8') as f:
   for r in csv.DictReader(f): rows+=f"<tr><td>{e(r.get('created_at'))}</td><td>{e(r.get('name'))}</td><td>{e(r.get('package'))}</td><td>{e(r.get('photographer'))}</td><td>{e(r.get('status'))}</td><td>{e(r.get('wants'))}</td></tr>"
 if not rows: rows='<tr><td colspan=6>No inquiries yet.</td></tr>'
 return layout('Tracker',f"<section class=section><h1>Booking Tracker</h1><p>Status system: {', '.join(STATUSES)}.</p><table><tr><th>Created</th><th>Client</th><th>Package</th><th>Photographer</th><th>Status</th><th>Wants</th></tr>{rows}</table></section>")
class H(BaseHTTPRequestHandler):
 def html(self,c,s=200):
  b=c.encode(); self.send_response(s); self.send_header('Content-Type','text/html; charset=utf-8'); self.send_header('Content-Length',str(len(b))); self.end_headers(); self.wfile.write(b)
 def do_GET(self):
  p=self.path.split('?',1)[0]; self.html(home() if p=='/' else packages() if p=='/packages' else photographers() if p=='/photographers' else book('success=1' in self.path) if p=='/book' else admin() if p=='/admin' else layout('Not found','<section class=section><h1>Page not found</h1></section>'), 200 if p in ['/','/packages','/photographers','/book','/admin'] else 404)
 def do_POST(self):
  if self.path!='/submit': self.html(layout('Not found',''),404); return
  save(parse_qs(self.rfile.read(int(self.headers.get('Content-Length',0))).decode())); self.send_response(303); self.send_header('Location','/book?success=1'); self.end_headers()
if __name__=='__main__':
 print(f'{BRAND} running on http://127.0.0.1:{PORT}'); HTTPServer(('0.0.0.0',PORT),H).serve_forever()
